import{_ as a,o as r,c as t,a2 as d}from"./chunks/framework.CuEaBji2.js";const i="/nginx-reverse-emby/screenshots/panel-wireguard-form.png",g=JSON.parse('{"title":"WireGuard 隧道","description":"","frontmatter":{},"headers":[],"relativePath":"guides/wireguard.md","filePath":"guides/wireguard.md","lastUpdated":1782021666000}'),s={name:"guides/wireguard.md"};function o(n,e,l,p,h,c){return r(),t("div",null,[...e[0]||(e[0]=[d('<h1 id="wireguard-隧道" tabindex="-1">WireGuard 隧道 <a class="header-anchor" href="#wireguard-隧道" aria-label="Permalink to &quot;WireGuard 隧道&quot;">​</a></h1><p>WireGuard 是一种快速、现代的 VPN 协议。在 nginx-reverse-emby 中，WireGuard 有三种用法：作为 Relay 的传输方式、作为 L4/HTTP 规则的入口、作为 L4/HTTP 规则的出口。</p><p>如果不需要 WireGuard，可以在控制面关闭：</p><div class="language-ini vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">NRE_WIREGUARD_ENABLED</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=false</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="wireguard-profile" tabindex="-1">WireGuard Profile <a class="header-anchor" href="#wireguard-profile" aria-label="Permalink to &quot;WireGuard Profile&quot;">​</a></h2><p>Profile 由控制面统一管理，包含私钥、监听端口、接口地址、Peer 配置等信息。Agent 会在节点上自动创建对应的 WireGuard 接口。私钥在面板中脱敏显示，编辑时保持脱敏值不变则保留已有密钥。</p><h3 id="创建-profile" tabindex="-1">创建 Profile <a class="header-anchor" href="#创建-profile" aria-label="Permalink to &quot;创建 Profile&quot;">​</a></h3><p>进入 <strong>基础设施 → WireGuard 配置</strong>，点击 <strong>新建</strong>：</p><table tabindex="0"><thead><tr><th>字段</th><th>示例</th><th>说明</th></tr></thead><tbody><tr><td>名称</td><td><code>edge-wg</code></td><td>Profile 名称</td></tr><tr><td>监听端口</td><td><code>51820</code></td><td>WireGuard UDP 监听端口</td></tr><tr><td>Private Key</td><td>留空</td><td>留空自动生成</td></tr><tr><td>MTU</td><td><code>1420</code></td><td>576–9000</td></tr><tr><td>Addresses</td><td><code>192.168.0.109</code></td><td>Agent 主机上 WireGuard socket 的物理监听地址。留空监听 <code>0.0.0.0</code></td></tr><tr><td>WG 分配地址</td><td><code>10.8.0.1/24</code></td><td>WireGuard 虚拟接口地址/地址池，支持 IPv4/IPv6，可填多行</td></tr><tr><td>DNS</td><td><code>1.1.1.1</code></td><td>接口 DNS</td></tr><tr><td>公网入口</td><td><code>vpn.example.com:51820</code></td><td>生成客户端配置用的公网地址</td></tr></tbody></table><p><img src="'+i+'" alt="WireGuard Profile 创建表单"></p><p><strong>Addresses</strong> 是 Agent 主机上 UDP socket 的物理监听地址，<strong>WG 分配地址</strong> 是 WireGuard 虚拟接口地址，两者不同。</p><p>WG 分配地址留空时，控制面从地址池自动分配。地址池配置：</p><div class="language-ini vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">NRE_WIREGUARD_AUTO_ADDRESS_POOLS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=10.8.x.1/24,fd10:8:x::1/64</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>模板中的 <code>x</code> 会被替换为递增序号。</p><h3 id="客户端" tabindex="-1">客户端 <a class="header-anchor" href="#客户端" aria-label="Permalink to &quot;客户端&quot;">​</a></h3><p>Profile 下可以创建客户端。控制面为每个客户端自动生成密钥对、分配地址，并导出标准客户端配置或 <code>wireguard://</code> URI，方便导入到手机或桌面客户端。</p><h2 id="三种用法" tabindex="-1">三种用法 <a class="header-anchor" href="#三种用法" aria-label="Permalink to &quot;三种用法&quot;">​</a></h2><h3 id="_1-relay-传输" tabindex="-1">1. Relay 传输 <a class="header-anchor" href="#_1-relay-传输" aria-label="Permalink to &quot;1. Relay 传输&quot;">​</a></h3><p>创建 Relay 监听器时，把传输方式设为 <code>wireguard</code>。Relay 的 TLS、mux、认证等功能仍然在 WireGuard 链路上生效。</p><h3 id="_2-l4-监听入口" tabindex="-1">2. L4 监听入口 <a class="header-anchor" href="#_2-l4-监听入口" aria-label="Permalink to &quot;2. L4 监听入口&quot;">​</a></h3><p>创建 L4 规则时，把监听模式设为 WireGuard。客户端需要先连接 Agent 的 WireGuard 端点，进入隧道后再访问规则配置的虚拟服务地址。</p><h3 id="_3-http-l4-出口" tabindex="-1">3. HTTP/L4 出口 <a class="header-anchor" href="#_3-http-l4-出口" aria-label="Permalink to &quot;3. HTTP/L4 出口&quot;">​</a></h3><p>把 HTTP 或 L4 规则的出口设为 WireGuard Profile，出站连接通过 WireGuard 发起。</p>',23)])])}const b=a(s,[["render",o]]);export{g as __pageData,b as default};
